column12:
{
  "note": "A widespread shortage of the popular Huy Fong Foods sriracha has led many to seek other spicy chili sauces.",
  "alts": [
    {
      "name_en": "Underwood Ranches Sriracha",
      "match": "Very close",
      "desc": "A sriracha-style sauce made by the original pepper grower for Huy Fong, offering a very comparable taste and consistency.",
      "where": "Condiment aisle or specialty foods section"
    },
    {
      "name_en": "Chili Garlic Sauce",
      "match": "Similar",
      "desc": "This sauce is chunkier and has a stronger garlic flavor than sriracha but a similar heat profile and ingredients.",
      "where": "Asian foods aisle or condiment aisle"
    },
    {
      "name_en": "Sambal Oelek",
      "match": "Similar",
      "desc": "A simple, raw chili paste with more pure pepper flavor and less sweetness than sriracha, often made by the same brands.",
      "where": "Asian foods aisle or condiment aisle"
    },
    {
      "name_en": "Gochujang",
      "match": "Similar",
      "desc": "This Korean fermented chili paste provides a unique sweet, savory, and spicy depth of flavor that is thicker than sriracha.",
      "where": "Asian foods aisle"
    }
  ]
}

column18:
{
  "note": "Sriracha may be unavailable due to supply shortages or personal preference for a different brand or heat level.",
  "alts": [
    {
      "name_en": "Huy Fong Chili Garlic Sauce",
      "match": "Similar",
      "desc": "Same brand as classic Sriracha but chunkier with more garlic and slightly less sweet heat.",
      "where": "Asian foods aisle or condiments section"
    },
    {
      "name_en": "Trader Joe's Sriracha Sauce",
      "match": "Very close",
      "desc": "A store-brand sriracha with a similar sweet, garlicky, tangy heat profile to the original.",
      "where": "Trader Joe's condiments aisle"
    },
    {
      "name_en": "Sky Valley Sriracha Sauce",
      "match": "Very close",
      "desc": "An organic sriracha alternative with nearly identical flavor and consistency to classic Huy Fong.",
      "where": "Natural/organic foods section or condiments aisle"
    },
    {
      "name_en": "Tabasco Sweet & Spicy Pepper Sauce",
      "match": "Similar",
      "desc": "Offers a comparable sweet-heat balance with a thinner consistency and mild vinegar tang.",
      "where": "Condiments aisle"
    }
  ]
}

column12:
{
  "note": "The user requires butter alternatives that are free from lactose due to an intolerance.",
  "alts": [
    {
      "name_en": "Vegan Butter Spread/Sticks",
      "match": "Similar",
      "desc": "A plant-based product made from oils specifically formulated to look, taste, and bake like dairy butter.",
      "where": "Refrigerated section, next to dairy butter and margarine."
    },
    {
      "name_en": "Coconut Oil",
      "match": "Different but works",
      "desc": "A solid plant-based fat that can be substituted 1:1 for butter in most baking and cooking applications.",
      "where": "Baking aisle or the oil and vinegar section."
    },
    {
      "name_en": "Olive Oil",
      "match": "Different but works",
      "desc": "A flavorful liquid fat used for sautéing, roasting, or as a finishing drizzle in place of melted butter.",
      "where": "Oil and vinegar aisle."
    }
  ]
}

column18:
{
  "note": "Butter contains lactose and can cause digestive issues for lactose intolerant individuals.",
  "alts": [
    {
      "name_en": "Earth Balance Vegan Butter",
      "match": "Very close",
      "desc": "Plant-based butter stick or spread that mimics the taste and function of dairy butter in cooking, baking, and spreading.",
      "where": "Dairy or natural foods aisle"
    },
    {
      "name_en": "Miyoko's Creamery Organic Vegan Butter",
      "match": "Very close",
      "desc": "Cashew-based vegan butter with a rich, creamy flavor very close to traditional dairy butter, suitable for all uses.",
      "where": "Dairy or natural foods aisle"
    },
    {
      "name_en": "Coconut Oil (refined)",
      "match": "Similar",
      "desc": "Refined coconut oil is solid at room temperature and works well as a 1:1 butter substitute in baking and sautéing without a coconut flavor.",
      "where": "Cooking oils aisle or natural foods section"
    },
    {
      "name_en": "Ghee (clarified butter)",
      "match": "Similar",
      "desc": "Butter with milk solids removed, making it virtually lactose-free while retaining a rich, buttery flavor ideal for cooking and baking.",
      "where": "International foods aisle or near cooking oils"
    }
  ]
}

column12:
{
  "note": "Rice vinegar provides a mild, slightly sweet acidity essential in many Asian dishes, and a substitute is needed when it is unavailable.",
  "alts": [
    {
      "name_en": "Apple Cider Vinegar",
      "match": "Similar",
      "desc": "This common vinegar has a fruitier, more robust flavor but provides the necessary acidity for dressings and marinades.",
      "where": "Condiments aisle, with other vinegars and oils."
    },
    {
      "name_en": "White Wine Vinegar",
      "match": "Similar",
      "desc": "It offers a clean, crisp acidity that is slightly less sweet but works well in most recipes calling for rice vinegar.",
      "where": "Condiments aisle, with other vinegars and oils."
    },
    {
      "name_en": "Champagne Vinegar",
      "match": "Similar",
      "desc": "As a very delicate and mild grape-based vinegar, its flavor profile is a close match for rice vinegar's subtlety.",
      "where": "Condiments aisle, often with specialty oils and vinegars."
    }
  ]
}

column18:
{
  "note": "Rice vinegar may be unavailable or you may need a substitute with similar mild acidity and slight sweetness.",
  "alts": [
    {
      "name_en": "Seasoned Rice Vinegar (e.g., Marukan or Nakano brand)",
      "match": "Very close",
      "desc": "Same rice vinegar base with added sugar and salt, works as a near-identical swap in most recipes.",
      "where": "Asian foods aisle or international section"
    },
    {
      "name_en": "White Wine Vinegar",
      "match": "Similar",
      "desc": "Mild, slightly fruity acidity that closely mimics rice vinegar's gentle tang without being overpowering.",
      "where": "Condiments/vinegar aisle"
    },
    {
      "name_en": "Apple Cider Vinegar",
      "match": "Similar",
      "desc": "Slightly stronger and fruitier than rice vinegar but shares a comparable mild acidity suitable for dressings and marinades.",
      "where": "Condiments/vinegar aisle or health foods section"
    },
    {
      "name_en": "Distilled White Vinegar (diluted)",
      "match": "Different but works",
      "desc": "Much sharper than rice vinegar, but diluting with a little water and a pinch of sugar brings it closer in balance.",
      "where": "Condiments/vinegar aisle"
    }
  ]
}

column12:
{
  "note": "Plant-based proteins are needed to replace the texture and protein content of chicken breast in vegetarian dishes.",
  "alts": [
    {
      "name_en": "Extra-Firm Tofu",
      "match": "Different but works",
      "desc": "This pressed soy-based block is excellent at absorbing marinades and can be baked or pan-fried to a chewy texture.",
      "where": "Refrigerated section, often near produce or in a dedicated vegetarian foods case"
    },
    {
      "name_en": "Seitan",
      "match": "Different but works",
      "desc": "Made from vital wheat gluten, seitan offers a uniquely dense, savory, and meat-like chew perfect for slicing or shredding.",
      "where": "Refrigerated section with other plant-based proteins like tofu and tempeh"
    },
    {
      "name_en": "Tempeh",
      "match": "Different but works",
      "desc": "A fermented soybean cake with a firm, nutty, and slightly earthy flavor that holds its shape well in stir-fries, sandwiches, or when grilled.",
      "where": "Refrigerated section, typically found alongside tofu"
    },
    {
      "name_en": "Plant-Based Chicken Cutlets",
      "match": "Different but works",
      "desc": "These processed soy or pea-protein products are specifically formulated to mimic the taste and texture of chicken breast.",
      "where": "Frozen foods aisle or refrigerated vegetarian section"
    }
  ]
}

column18:
{
  "note": "Chicken breast is animal meat and not suitable for a vegetarian diet, so plant-based protein alternatives are needed.",
  "alts": [
    {
      "name_en": "Extra-Firm Tofu",
      "match": "Different but works",
      "desc": "A dense, protein-rich soy product that can be pressed, sliced, and cooked to mimic the texture of chicken breast in stir-fries, sandwiches, and bakes.",
      "where": "Refrigerated produce section or natural foods aisle"
    },
    {
      "name_en": "Seitan (Wheat Meat)",
      "match": "Different but works",
      "desc": "Made from vital wheat gluten, seitan has a chewy, meaty texture that closely resembles cooked chicken and absorbs marinades and seasonings very well.",
      "where": "Refrigerated natural foods or health food section"
    },
    {
      "name_en": "Jackfruit (Young/Green, Canned)",
      "match": "Different but works",
      "desc": "Young green jackfruit has a fibrous, shreddable texture similar to pulled chicken and works well in tacos, curries, and sandwiches.",
      "where": "Canned goods aisle or international foods section"
    },
    {
      "name_en": "Gardein Chick'n Scallopini",
      "match": "Similar",
      "desc": "A frozen plant-based product specifically designed to replicate the shape, size, and mild flavor of a chicken breast cutlet.",
      "where": "Frozen foods aisle, plant-based or meatless section"
    }
  ]
}

column12:
{
  "note": "Fish sauce provides a foundational salty and umami flavor, and Korean cuisine has several authentic ingredients that serve a similar purpose.",
  "alts": [
    {
      "name_en": "Korean Fish Sauce (Aekjeot)",
      "match": "Very close",
      "desc": "This is the Korean equivalent of Southeast Asian fish sauce, providing the same salty, umami depth essential for dishes like kimchi.",
      "where": "Asian foods aisle or a Korean/Asian grocery store"
    },
    {
      "name_en": "Korean Soup Soy Sauce (Guk-ganjang)",
      "match": "Similar",
      "desc": "A traditional Korean soy sauce that is saltier and has a more complex fermented flavor than regular soy sauce, often used to season soups.",
      "where": "Asian foods aisle or a Korean/Asian grocery store"
    },
    {
      "name_en": "Korean Fermented Salted Shrimp (Saeu-jeot)",
      "match": "Similar",
      "desc": "This fermented shrimp paste delivers a potent, salty seafood umami that is a hallmark of many Korean recipes, especially kimchi and stews.",
      "where": "Refrigerated section of a Korean/Asian grocery store"
    },
    {
      "name_en": "Korean Fermented Soybean Paste (Doenjang)",
      "match": "Different but works",
      "desc": "A rich, salty paste made from fermented soybeans that provides a deep, earthy umami flavor distinct from but complementary to fish sauce.",
      "where": "Asian foods aisle or a Korean/Asian grocery store"
    }
  ]
}

column18:
{
  "note": "Fish sauce may be unavailable or needed in a Korean-friendly form for umami depth in marinades, kimchi, and stews.",
  "alts": [
    {
      "name_en": "Saeujeot (Korean Salted Fermented Shrimp)",
      "match": "Similar",
      "desc": "A staple Korean fermented condiment that delivers the same briny, funky umami punch used authentically in kimchi and Korean soups.",
      "where": "Asian grocery store, refrigerated section or jarred condiments aisle"
    },
    {
      "name_en": "Soup Soy Sauce (Guk-ganjang / Korean Soup Soy Sauce)",
      "match": "Similar",
      "desc": "A thin, salty, deeply fermented Korean soy sauce traditionally used to season soups and stews as a direct stand-in for fish sauce.",
      "where": "Asian grocery store, soy sauce / condiments aisle"
    },
    {
      "name_en": "Anchovy Broth Concentrate (Korean Myeolchi Aekjeot / Anchovy Fish Sauce)",
      "match": "Very close",
      "desc": "A Korean-style anchovy-based liquid seasoning that is essentially the same product as fish sauce but specifically formulated for Korean cooking.",
      "where": "Asian grocery store, condiments or soup base aisle"
    },
    {
      "name_en": "Soy Sauce (Regular)",
      "match": "Different but works",
      "desc": "Widely available and provides saltiness and umami, though it lacks the fermented seafood depth; works as a quick substitute in Korean recipes.",
      "where": "Any grocery store, condiments or international foods aisle"
    }
  ]
}
